const webhookData = $('Webhook').first().json.body;

const fileData = $input.first().json;
let dv2Rules;
try {
  if (fileData.data) {
    dv2Rules = JSON.parse(Buffer.from(fileData.data, 'base64').toString('utf-8'));
  } else if (fileData.json) {
    dv2Rules = typeof fileData.json === 'string' ? JSON.parse(fileData.json) : fileData.json;
  } else {
    dv2Rules = fileData;
  }
} catch (e) {
  dv2Rules = fileData;
}

return {
  json: {
    vault_tables: webhookData.vault_tables || [],
    mart_table: webhookData.mart_table || null,
    dv2_rules: dv2Rules
  }
};

