const llmOutput = $input.first().json.text;

let parsed;
try {
  parsed = JSON.parse(llmOutput);
} catch (e) {
  let jsonStr = llmOutput;
  const fenceMatch = llmOutput.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (fenceMatch) {
    jsonStr = fenceMatch[1].trim();
  } else if (llmOutput.startsWith('```')) {
    jsonStr = llmOutput.replace(/^```(?:json)?\s*/, '').trim();
  }

  try {
    parsed = JSON.parse(jsonStr);
  } catch (e2) {
    // Attempt to recover truncated JSON
    let recovered = jsonStr;
    const quoteCount = (recovered.match(/(?<!\\)"/g) || []).length;
    if (quoteCount % 2 !== 0) recovered += '"';
    const stack = [];
    for (const ch of recovered) {
      if (ch === '{' || ch === '[') stack.push(ch);
      else if (ch === '}' || ch === ']') stack.pop();
    }
    while (stack.length > 0) {
      const last = stack.pop();
      recovered += last === '{' ? '}' : ']';
    }
    try {
      parsed = JSON.parse(recovered);
    } catch (e3) {
      throw new Error('Could not parse LLM output as JSON: ' + llmOutput.substring(0, 300));
    }
  }
}

if (!parsed.sql) {
  throw new Error('LLM output missing sql field');
}

return {
  json: {
    sql: parsed.sql,
    checks_count: parsed.checks_count || 0
  }
};

const queryResult = $input.first().json;
const checksCount = $('Parse SQL').first().json.checks_count;

// Handle query errors
if (queryResult.detail || queryResult.status === 'error') {
  return {
    json: {
      status: 'error',
      checks_run: 0,
      issues: [{
        severity: 'error',
        table: '_validation_query',
        check: 'SYSTEM',
        message: 'Validation query failed: ' + (queryResult.detail || 'unknown error'),
        count: 0
      }]
    }
  };
}

const rows = queryResult.rows || [];
const issues = [];

for (const row of rows) {
  const count = parseInt(row.issue_count, 10);
  if (count > 0) {
    issues.push({
      severity: 'error',
      table: row.table_name,
      check: row.category,
      message: row.message + ' (' + count + ' rows)',
      count: count
    });
  }
}

const hasErrors = issues.length > 0;

return {
  json: {
    status: hasErrors ? 'fail' : 'pass',
    checks_run: rows.length || checksCount,
    issues: issues
  }
};
